struct ForgePress {
    var pressure: Int

    var bars: Int {
        get {
            return pressure / 10
        }
        set {
            pressure = newValue * 10
        }
    }
}

var press = ForgePress(pressure: 50)
print("Initial Bars: \(press.bars)")
press.bars = 12
print("Final Internal Pressure: \(press.pressure)")

